 8→class ChannelManagerService
 9→{
10→    public function book(array $bookingData): array
11→    {
12→        // Simulate slow network response (1 to 4 seconds)
13→        sleep(rand(1, 4));
14→
15→        // Simulate a 25% chance of the external API failing or timing out
16→        if (rand(1, 4) === 1) {
17→            Log::warning('ChannelManagerService: Connection timeout or 503 Service Unavailable.');
18→            throw new Exception('Channel Manager API is currently unreachable. Please try again.');
19→        }
20→
21→        $confirmationId = 'OTA-' . strtoupper(uniqid());
22→        Log::info("ChannelManagerService: Booking {$confirmationId} confirmed successfully.", $bookingData);
23→
24→        return [
25→            'status' => 'confirmed',
26→            'external_confirmation_id' => $confirmationId,
27→            'timestamp' => now()->toIso8601String(),
28→        ];
29→    }
30→}
